import anthropic, json

client = anthropic.Anthropic()

def detect_aup_violation_patterns(
    violation_log: list[dict],    # [{user_id, department, tool, rule_violated, timestamp}]
    analysis_period: str,
) -> dict:
    """
    Analyse a set of AUP violation logs to detect patterns that suggest
    systemic issues (tool design problems, training gaps, department-level
    misuse) rather than isolated individual violations.
    """
    # Aggregate simple stats in Python before sending to Claude
    rule_counts = {}
    dept_counts = {}
    tool_counts = {}
    for v in violation_log:
        rule_counts[v.get("rule_violated", "unknown")] = rule_counts.get(v.get("rule_violated", "unknown"), 0) + 1
        dept_counts[v.get("department", "unknown")] = dept_counts.get(v.get("department", "unknown"), 0) + 1
        tool_counts[v.get("tool", "unknown")] = tool_counts.get(v.get("tool", "unknown"), 0) + 1

    prompt = f"""
You are an AI governance analyst detecting systemic AUP violation patterns.

Analysis period: {analysis_period}
Total violations: {len(violation_log)}

Rule violation frequency:
{json.dumps(rule_counts, indent=2)}

Department violation frequency:
{json.dumps(dept_counts, indent=2)}

Tool violation frequency:
{json.dumps(tool_counts, indent=2)}

Identify patterns that suggest:
1. Tool design problems (high violations on one tool → the tool makes AUP violation too easy)
2. Training gaps (high violations in one department → that department needs training)
3. Policy ambiguity (many violations on the same rule → the rule is unclear)
4. Isolated bad actors (one user responsible for many violations)

Return ONLY JSON:
{{
  "systemic_issues": ["<string>", ...],
  "tool_redesign_recommendations": ["<string>", ...],
  "training_recommendations": ["<string>", ...],
  "policy_clarification_needed": ["<string>", ...],
  "escalation_candidates": ["<string>", ...],
  "overall_risk_trend": "improving" | "stable" | "worsening"
}}
""".strip()

    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=600,
        messages=[{"role": "user", "content": prompt}]
    )
    return json.loads(response.content[0].text)
